332	    let o = order.unwrap();
333	    assert_eq!(o["status"], "Reserved", "New order starts as Reserved");
334	    assert!(o["payment_deadline"].is_string(), "Must have payment deadline");
335	
336	    // Payment simulation needs order_id + amount + outcome
337	    let payment_args = (
338	        o["id"].as_str().unwrap(),
339	        o["total"].as_f64().unwrap(),
340	        "Success",
