361	/// Test: Rating submission dimension construction
362	#[test]
363	fn test_rating_submission_builds_dimensions() {
364	    let dimensions = vec!["Plot", "Acting", "Visuals", "Soundtrack", "Dialogue", "Pacing"];
365	    let scores: Vec<(String, u32)> = dimensions
366	        .iter()
367	        .map(|d| (d.to_string(), 5u32))
368	        .collect();
369	
370	    // Build the request payload
371	    let dims: Vec<serde_json::Value> = scores
372	        .iter()
373	        .map(|(name, score)| {
374	            serde_json::json!({
375	                "dimension_name": name,
376	                "score": score
377	            })
378	        })
379	        .collect();
380	
381	    let request = serde_json::json!({
382	        "product_id": "prod-uuid",
383	        "dimensions": dims
384	    });
385	
386	    // Must use dimension_name and dimensions, not overall_score/review_text
387	    assert!(request["dimensions"].is_array());
388	    assert_eq!(request["dimensions"].as_array().unwrap().len(), 6);
389	    assert!(request.get("overall_score").is_none());
390	    assert!(request.get("review_text").is_none());
391	
392	    for dim in request["dimensions"].as_array().unwrap() {
393	        assert!(dim["dimension_name"].is_string());
394	        let score = dim["score"].as_u64().unwrap();
395	        assert!(score >= 1 && score <= 10, "Score {} out of range", score);
396	    }
397	}
