399	/// Test: Rating score change propagation
400	#[test]
401	fn test_rating_score_change() {
402	    let mut scores: Vec<(String, u32)> = vec![
403	        ("Plot".into(), 5),
404	        ("Acting".into(), 5),
405	        ("Visuals".into(), 5),
406	    ];
407	
408	    // Simulate changing "Acting" to 9
409	    if let Some(entry) = scores.iter_mut().find(|(d, _)| d == "Acting") {
410	        entry.1 = 9;
411	    }
412	
413	    assert_eq!(scores[1].1, 9u32, "Score must update to 9");
414	
415	    // Computed average
416	    let avg: f64 = scores.iter().map(|(_, s)| *s as f64).sum::<f64>() / scores.len() as f64;
417	    assert!((avg - 6.333).abs() < 0.01);
418	}
