1	use gloo::storage::{LocalStorage, Storage};
2	use crate::types::UserResponse;
3	
4	const ACCESS_TOKEN_KEY: &str = "silverscreen_access_token";
5	const REFRESH_TOKEN_KEY: &str = "silverscreen_refresh_token";
6	const USER_KEY: &str = "silverscreen_user";
7	
8	pub fn save_tokens(access: &str, refresh: &str) {
9	    let _ = LocalStorage::set(ACCESS_TOKEN_KEY, access.to_string());
10	    let _ = LocalStorage::set(REFRESH_TOKEN_KEY, refresh.to_string());
11	}
12	
13	pub fn get_access_token() -> Option<String> {
14	    LocalStorage::get::<String>(ACCESS_TOKEN_KEY).ok()
15	}
16	
17	pub fn get_refresh_token() -> Option<String> {
18	    LocalStorage::get::<String>(REFRESH_TOKEN_KEY).ok()
19	}
20	
21	pub fn clear_tokens() {
22	    LocalStorage::delete(ACCESS_TOKEN_KEY);
23	    LocalStorage::delete(REFRESH_TOKEN_KEY);
24	    LocalStorage::delete(USER_KEY);
25	}
26	
27	pub fn save_user(user: &UserResponse) {
28	    if let Ok(json) = serde_json::to_string(user) {
29	        let _ = LocalStorage::set(USER_KEY, json);
30	    }
31	}
32	
33	pub fn get_user() -> Option<UserResponse> {
34	    LocalStorage::get::<String>(USER_KEY)
35	        .ok()
36	        .and_then(|json| serde_json::from_str(&json).ok())
37	}
38	
39	pub fn is_authenticated() -> bool {
40	    get_access_token().is_some()
41	}
42	
43	pub fn get_role() -> Option<String> {
44	    get_user().map(|u| u.role)
45	}
