76	fn switch(route: Route) -> Html {
77	    match route {
78	        Route::Home | Route::Catalog => html! { <HomePage /> },
79	        Route::Login => html! { <LoginPage /> },
80	        Route::Register => html! { <RegisterPage /> },
81	        Route::ProductDetail { id } => html! { <ProductDetailPage id={id} /> },
82	        Route::Cart => html! { <CartPage /> },
83	        Route::Checkout => html! { <CheckoutPage /> },
84	        Route::Orders => html! { <OrdersPage /> },
85	        Route::OrderDetail { id } => html! { <OrderDetailPage id={id} /> },
86	        Route::RateProduct { product_id } => html! { <RateProductPage product_id={product_id} /> },
87	        Route::Leaderboards => html! { <LeaderboardsPage /> },
88	        Route::ReviewerRounds => html! { <ReviewerRoundsPage /> },
89	        Route::ReviewerSubmit { id } => html! { <ReviewerSubmitPage id={id} /> },
90	        Route::Admin => html! { <AdminDashboard /> },
91	        Route::AdminUsers => html! { <AdminUsersPage /> },
92	        Route::AdminTaxonomy => html! { <AdminTaxonomyPage /> },
93	        Route::AdminFields => html! { <AdminFieldsPage /> },
94	        Route::AdminModeration => html! { <AdminModerationPage /> },
95	        Route::AdminAudit => html! { <AdminAuditLogPage /> },
96	        Route::AdminReports => html! { <AdminReportsPage /> },
97	        Route::AdminBackup => html! { <AdminBackupPage /> },
98	        Route::NotFound => html! {
99	            <div class="page-center">
100	                <div class="empty-state">
101	                    <h1>{ "404" }</h1>
102	                    <p>{ "Page not found" }</p>
103	                    <Link<Route> to={Route::Home} classes="btn btn-primary">{ "Go Home" }</Link<Route>>
104	                </div>
105	            </div>
106	        },
107	    }
108	}
109	
110	#[function_component(App)]
111	pub fn app() -> Html {
112	    let cart_count = use_state(|| 0u32);
113	    let toast = use_toast();
114	    // Force re-render trigger on auth state change
115	    let auth_version = use_state(|| 0u32);
116	
117	    // Fetch cart count periodically
118	    {
119	        let cart_count = cart_count.clone();
120	        let auth_ver = *auth_version;
121	        use_effect_with(auth_ver, move |_| {
122	            let cart_count = cart_count.clone();
123	            if store::is_authenticated() {
124	                spawn_local(async move {
125	                    if let Ok(c) = api::cart::get_cart().await {
126	                        cart_count.set(c.items.iter().map(|i| i.quantity).sum());
127	                    }
128	                });
129	            } else {
130	                cart_count.set(0);
131	            }
132	            || ()
133	        });
134	    }
135	
136	    let on_logout = {
137	        let auth_version = auth_version.clone();
138	        let toast = toast.clone();
139	        Callback::from(move |_: ()| {
140	            let auth_version = auth_version.clone();
141	            let toast = toast.clone();
142	            spawn_local(async move {
143	                let _ = api::auth::logout().await;
144	                store::clear_tokens();
145	                auth_version.set(*auth_version + 1);
146	                toast.info("Logged out successfully.");
147	            });
148	        })
149	    };
150	
151	    html! {
152	        <BrowserRouter>
153	            <div class="app-layout">
154	                <Navbar cart_count={*cart_count} on_logout={on_logout} />
155	                <main class="main-content">
156	                    <Switch<Route> render={switch} />
157	                </main>
158	                <ToastContainer manager={toast} />
159	            </div>
160	        </BrowserRouter>
161	    }
162	}
