56	impl Config {
57	    /// Returns a reference to the global configuration singleton.
58	    pub fn get() -> &'static Config {
59	        &CONFIG
60	    }
61	
62	    /// Validates that no placeholder/default secrets are used in non-local environments.
63	    /// Called at startup to prevent insecure deployments.
64	    pub fn validate_secrets(&self) {
65	        // Known unsafe values: old hardcoded defaults + local dev defaults + .env.example placeholders
66	        let reject_jwt = [
67	            "silverscreen_jwt_secret_change_in_production_2024",
68	            "local_dev_jwt_secret_not_for_prod_use_64_chars_min_xxxxxx",
69	            "CHANGE_ME_use_openssl_rand_hex_64_to_generate",
70	        ];
71	        let reject_enc = [
72	            "0123456789abcdef0123456789abcdef",
73	            "local_dev_encrypt_key_32bytes!!!",
74	            "CHANGE_ME_use_openssl_rand_hex_32",
75	        ];
76	        let reject_backup = [
77	            "backup_encryption_key_change_in_production",
78	            "local_dev_backup_key_not_for_prod",
79	            "CHANGE_ME_use_a_different_random_key",
80	        ];
81	
82	        // Check JWT_SECRET — reject known placeholders in ALL environments.
83	        // A weak JWT secret is dangerous even in local dev (tokens are portable).
84	        if reject_jwt.contains(&self.jwt_secret.as_str()) {
85	            panic!("SECURITY: JWT_SECRET is a known default/placeholder. Generate a real secret with `openssl rand -hex 64`.");
86	        }
87	
88	        // Check ENCRYPTION_KEY — reject known placeholders in ALL environments.
89	        // Encrypted data produced with a placeholder key is trivially decryptable.
90	        if reject_enc.contains(&self.encryption_key.as_str()) {
91	            panic!("SECURITY: ENCRYPTION_KEY is a known default/placeholder. Generate a real 32-byte key with `openssl rand -hex 16`.");
92	        }
93	
94	        // Check BACKUP_ENCRYPTION_KEY — reject known placeholders in ALL environments.
95	        // A weak backup key means backups are trivially decryptable.
96	        if reject_backup.contains(&self.backup_encryption_key.as_str()) {
97	            panic!("SECURITY: BACKUP_ENCRYPTION_KEY is a known default/placeholder. Generate a real key with `openssl rand -hex 32`.");
98	        }
99	
100	        // --- Key strength validation (runs in ALL environments) ---
101	
102	        // BACKUP_ENCRYPTION_KEY: must not be empty, must be at least 16 chars
103	        if self.backup_encryption_key.is_empty() {
104	            panic!("SECURITY: BACKUP_ENCRYPTION_KEY is empty. Set a non-empty encryption key.");
105	        }
106	        if self.backup_encryption_key.len() < 16 {
107	            panic!(
108	                "SECURITY: BACKUP_ENCRYPTION_KEY is too short ({} chars). Minimum 16 characters required.",
109	                self.backup_encryption_key.len()
110	            );
111	        }
112	
113	        // ENCRYPTION_KEY: must be exactly 32 bytes for AES-256
114	        if self.encryption_key.len() != 32 {
115	            panic!(
116	                "SECURITY: ENCRYPTION_KEY must be exactly 32 bytes (got {}). Use `openssl rand -hex 16` to generate.",
117	                self.encryption_key.len()
118	            );
119	        }
120	
121	        // JWT_SECRET: must be at least 32 chars for HMAC security
122	        if self.jwt_secret.len() < 32 {
123	            panic!(
124	                "SECURITY: JWT_SECRET is too short ({} chars). Minimum 32 characters required.",
125	                self.jwt_secret.len()
126	            );
127	        }
128	
129	        // Also reject any value containing "CHANGE_ME" in ALL environments
130	        for (name, val) in [
131	            ("JWT_SECRET", &self.jwt_secret),
132	            ("ENCRYPTION_KEY", &self.encryption_key),
133	            ("BACKUP_ENCRYPTION_KEY", &self.backup_encryption_key),
134	        ] {
135	            if val.contains("CHANGE_ME") {
136	                panic!("SECURITY: {} contains 'CHANGE_ME' — replace with a real secret.", name);
137	            }
138	        }
139	    }
