706	/// Simulate changing a rating score and verify the average recomputes correctly.
707	#[test]
708	fn test_rating_score_update_recomputes_average() {
709	    let mut scores: Vec<DimensionScore> = vec![
710	        DimensionScore { dimension_name: "Plot".into(), score: 5 },
711	        DimensionScore { dimension_name: "Acting".into(), score: 5 },
712	        DimensionScore { dimension_name: "Visuals".into(), score: 5 },
713	    ];
714	
715	    // User changes "Acting" to 9
716	    if let Some(dim) = scores.iter_mut().find(|d| d.dimension_name == "Acting") {
717	        dim.score = 9;
718	    }
719	
720	    assert_eq!(scores[1].score, 9);
721	
722	    // Computed average: (5 + 9 + 5) / 3 = 6.333...
723	    let avg: f64 = scores.iter().map(|d| d.score as f64).sum::<f64>() / scores.len() as f64;
724	    assert!((avg - 6.333).abs() < 0.01);
725	
726	    // Build the final request with updated scores
727	    let request = CreateRatingRequest {
728	        product_id: "prod-uuid".to_string(),
729	        dimensions: scores,
730	    };
731	    assert_eq!(request.dimensions[1].score, 9);
732	}
